109→// ---- 3.2  Components ------------------------------------------------------
110→
111→export type SDUIPropValue =
112→  | string
113→  | number
114→  | boolean
115→  | null
116→  | SDUIConditional
117→  | SDUIValidation
118→  | SDUIRichText
119→  | SDUIPropValue[]
